package com.company.hr;

import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.ws.Endpoint;
import java.util.HashMap;
import java.util.Map;

@WebService
public class EmployeeManagementService {

    private Map<Integer, Employee> employeeDatabase = new HashMap<>();

    @WebMethod
    public String updateSalary(int employeeId, double newSalary) {
        Employee employee = employeeDatabase.get(employeeId);
        if (employee != null) {
            employee.setSalary(newSalary);
            return "Salary updated successfully.";
        }
        return "Employee not found.";
    }

    @WebMethod
    public String addPerformanceReview(int employeeId, String review) {
        Employee employee = employeeDatabase.get(employeeId);
        if (employee != null) {
            employee.addPerformanceReview(review);
            return "Performance review added successfully.";
        }
        return "Employee not found.";
    }

    @WebMethod
    public String terminateEmployee(int employeeId) {
        if (employeeDatabase.containsKey(employeeId)) {
            employeeDatabase.remove(employeeId);
            return "Employee terminated successfully.";
        }
        return "Employee not found.";
    }

    private static class Employee {
        private int id;
        private double salary;
        private String performanceReviews;

        public Employee(int id, double salary) {
            this.id = id;
            this.salary = salary;
            this.performanceReviews = "";
        }

        public void setSalary(double salary) {
            this.salary = salary;
        }

        public void addPerformanceReview(String review) {
            this.performanceReviews += review + "\n";
        }
    }

    public static void main(String[] args) {
        EmployeeManagementService service = new EmployeeManagementService();
        service.employeeDatabase.put(1, new Employee(1, 50000));
        service.employeeDatabase.put(2, new Employee(2, 60000));

        String address = "http://localhost:8080/EmployeeManagementService";
        Endpoint.publish(address, service);
        System.out.println("Service published at " + address);
    }
}